using ModelContextProtocol.Server;
using System.ComponentModel;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "MyMcpServer", Version = "1.0.0" };
    })
    .WithHttpTransport()
    .WithToolsFromAssembly()
    .WithResources<ConfigResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

// --- Tools ---

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool, Description("Returns the current server UTC time.")]
    public static string GetServerTime() => DateTime.UtcNow.ToString("O");
}

// --- Resources ---

[McpServerResourceType]
public class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings",
        Name = "App Settings",
        Description = "Returns the application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxConnections = 100,
            FeatureFlags = new { DarkMode = true, BetaFeatures = false },
            Version = "1.0.0"
        };
        return System.Text.Json.JsonSerializer.Serialize(config,
            new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/status",
        Name = "Server Status",
        Description = "Returns current server health status.")]
    public static string GetServerStatus()
    {
        return System.Text.Json.JsonSerializer.Serialize(new
        {
            Status = "Healthy",
            Uptime = Environment.TickCount64 / 1000,
            Timestamp = DateTime.UtcNow
        }, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }
}

